import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  if (!cameraData?.imagePreview) {
    return (
      <div style={{ padding: '40px', textAlign: 'center', color: '#555' }}>
        <p>Không có ảnh camera để vẽ zone.</p>
        <button 
          onClick={onBack}
          style={{ padding: '10px 24px', fontSize: '16px' }}
        >
          ← Quay lại
        </button>
      </div>
    );
  }

  const [currentStep, setCurrentStep] = useState(1); // 1: Axis, 2: Coord, 3: Polygon
  const [drawing, setDrawing] = useState(false);
  const [zones, setZones] = useState([]);
  const [currentZone, setCurrentZone] = useState({
    name: '',
    lines: [],        // [axis, coord]
    polyPoints: [],   // ≥ 3 điểm
  });
  const [zoneName, setZoneName] = useState('');
  const [selectedZoneIndex, setSelectedZoneIndex] = useState(null);

  const canvasRef = useRef(null);
  const FIXED_WIDTH = 800;
  const FIXED_HEIGHT = 450;

  // Khởi tạo kích thước canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas) {
      canvas.width = FIXED_WIDTH;
      canvas.height = FIXED_HEIGHT;
    }
  }, []);

  // Load ảnh nền + redraw khi cần
  useEffect(() => {
    redrawAll();
  }, [cameraData.imagePreview, zones, currentZone, selectedZoneIndex]);

  const loadBackground = (callback) => {
    if (!cameraData.imagePreview) return;
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.src = cameraData.imagePreview;
    img.onload = () => callback(img);
  };

  const redrawAll = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    // Xóa + vẽ nền
    ctx.clearRect(0, 0, FIXED_WIDTH, FIXED_HEIGHT);
    loadBackground((img) => {
      ctx.drawImage(img, 0, 0, FIXED_WIDTH, FIXED_HEIGHT);

      // Vẽ các zone đã hoàn thành
      zones.forEach((zone, i) => {
        drawZone(ctx, zone, i === selectedZoneIndex);
      });

      // Vẽ zone đang chỉnh sửa
      if (currentZone.lines.length > 0 || currentZone.polyPoints.length > 0) {
        drawZone(ctx, currentZone, true);
      }
    });
  };

  // ────────────────────────────────────────────────
  //              Vẽ các thành phần
  // ────────────────────────────────────────────────

  const drawPoint = (ctx, x, y, label = '', color = '#e74c3c') => {
    ctx.beginPath();
    ctx.arc(x, y, 7, 0, Math.PI * 2);
    ctx.fillStyle = color;
    ctx.fill();
    ctx.strokeStyle = 'white';
    ctx.lineWidth = 2.5;
    ctx.stroke();

    if (label) {
      ctx.fillStyle = 'white';
      ctx.font = 'bold 13px Arial';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(label, x, y);
    }
  };

  const drawLine = (ctx, x1, y1, x2, y2, color, width = 2.5, dashed = false) => {
    ctx.beginPath();
    ctx.moveTo(x1, y1);
    ctx.lineTo(x2, y2);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    if (dashed) ctx.setLineDash([6, 4]);
    ctx.stroke();
    ctx.setLineDash([]);
  };

  const drawArrow = (ctx, x1, y1, x2, y2, color, width = 3) => {
    const headlen = 18;
    const dx = x2 - x1;
    const dy = y2 - y1;
    const angle = Math.atan2(dy, dx);

    drawLine(ctx, x1, y1, x2, y2, color, width);

    ctx.beginPath();
    ctx.moveTo(x2, y2);
    ctx.lineTo(
      x2 - headlen * Math.cos(angle - Math.PI / 6),
      y2 - headlen * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      x2 - headlen * Math.cos(angle + Math.PI / 6),
      y2 - headlen * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  const drawZone = (ctx, zone, isActive = false) => {
    const color = isActive ? '#e74c3c' : '#27ae60';
    const lineWidth = isActive ? 3.5 : 2.5;

    // Axis (đường thẳng đen)
    if (zone.lines[0]) {
      const [x1, y1, x2, y2] = zone.lines[0];
      drawLine(ctx, x1, y1, x2, y2, isActive ? '#e74c3c' : '#2c3e50', lineWidth);
    }

    // Coord (mũi tên đỏ)
    if (zone.lines[1]) {
      const [x1, y1, x2, y2] = zone.lines[1];
      drawArrow(ctx, x1, y1, x2, y2, isActive ? '#c0392b' : '#c0392b', lineWidth);
    }

    // Polygon
    if (zone.polyPoints.length >= 3) {
      ctx.beginPath();
      ctx.moveTo(zone.polyPoints[0].x, zone.polyPoints[0].y);
      zone.polyPoints.forEach(p => ctx.lineTo(p.x, p.y));
      ctx.closePath();

      ctx.fillStyle = isActive ? 'rgba(231, 76, 60, 0.12)' : 'rgba(39, 174, 96, 0.10)';
      ctx.fill();

      ctx.strokeStyle = color;
      ctx.lineWidth = isActive ? 3 : 2;
      ctx.stroke();

      // Điểm + số thứ tự
      zone.polyPoints.forEach((p, i) => {
        drawPoint(ctx, p.x, p.y, String(i + 1), color);
      });
    }

    // Tên zone
    if (zone.name && zone.polyPoints.length >= 3) {
      const avgX = zone.polyPoints.reduce((s, p) => s + p.x, 0) / zone.polyPoints.length;
      const avgY = zone.polyPoints.reduce((s, p) => s + p.y, 0) / zone.polyPoints.length;

      ctx.font = 'bold 15px Arial';
      ctx.fillStyle = isActive ? '#c0392b' : '#2c3e50';
      ctx.textAlign = 'center';
      ctx.fillText(zone.name, avgX, avgY - 25);
    }
  };

  // ────────────────────────────────────────────────
  //              Xử lý sự kiện chuột
  // ────────────────────────────────────────────────

  const getScaledPos = (e) => {
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = FIXED_WIDTH / rect.width;
    const scaleY = FIXED_HEIGHT / rect.height;
    return {
      x: (e.clientX - rect.left) * scaleX,
      y: (e.clientY - rect.top) * scaleY,
    };
  };

  const handleMouseDown = (e) => {
    if (currentStep === 3) {
      // Polygon mode → thêm điểm
      const pos = getScaledPos(e);
      if (pos.x < 0 || pos.x > FIXED_WIDTH || pos.y < 0 || pos.y > FIXED_HEIGHT) return;

      setCurrentZone(prev => ({
        ...prev,
        polyPoints: [...prev.polyPoints, pos],
      }));
    } else {
      // Axis & Coord mode
      const pos = getScaledPos(e);
      setDrawing(true);
      setCurrentZone(prev => ({
        ...prev,
        tempStart: pos,
      }));
    }
  };

  const handleMouseMove = (e) => {
    if (!drawing || currentStep === 3) return;
    const pos = getScaledPos(e);

    const ctx = canvasRef.current.getContext('2d');
    redrawAll();

    const { tempStart: start } = currentZone;
    if (!start) return;

    if (currentStep === 1) {
      drawLine(ctx, start.x, start.y, pos.x, pos.y, '#2c3e50', 2, true);
    } else if (currentStep === 2) {
      drawArrow(ctx, start.x, start.y, pos.x, pos.y, '#e74c3c', 3);
    }
  };

  const handleMouseUp = (e) => {
    if (!drawing || currentStep === 3) return;
    setDrawing(false);

    const pos = getScaledPos(e);
    const { tempStart: start } = currentZone;
    if (!start) return;

    const newLine = [start.x, start.y, pos.x, pos.y];

    setCurrentZone(prev => ({
      ...prev,
      lines: [...prev.lines, newLine],
      tempStart: null,
    }));

    if (currentStep === 1) setCurrentStep(2);
    else if (currentStep === 2) setCurrentStep(3);
  };

  const completeCurrentZone = () => {
    if (!zoneName.trim()) {
      alert('Vui lòng đặt tên cho zone!');
      return;
    }
    if (currentZone.lines.length < 2) {
      alert('Cần vẽ cả Axis và Coord!');
      return;
    }
    if (currentZone.polyPoints.length < 3) {
      alert('Cần ít nhất 3 điểm để tạo polygon!');
      return;
    }

    const newZone = {
      name: zoneName.trim(),
      lines: currentZone.lines,
      polyPoints: currentZone.polyPoints,
    };

    setZones(prev => [...prev, newZone]);
    resetCurrentZone();
    setSelectedZoneIndex(zones.length);
  };

  const resetCurrentZone = () => {
    setCurrentZone({ name: '', lines: [], polyPoints: [] });
    setZoneName('');
    setCurrentStep(1);
    setDrawing(false);
  };

  const deleteZone = (index) => {
    setZones(prev => prev.filter((_, i) => i !== index));
    if (selectedZoneIndex === index) setSelectedZoneIndex(null);
  };

  // ────────────────────────────────────────────────
  //              Generate Output
  // ────────────────────────────────────────────────

  const generateOutput = () => {
    const formattedZones = zones.map((zone, idx) => {
      const axis = zone.lines[0] || [0, 0, 0, 0];
      const coord = zone.lines[1] || [0, 0, 0, 0];

      return {
        ID: crypto.randomUUID?.() || `zone-${idx + 1}-${Date.now()}`,
        name: zone.name,
        type: 1,
        axis: axis.map(v => Number((v / (v < FIXED_WIDTH ? FIXED_WIDTH : FIXED_HEIGHT)).toFixed(3))),
        coord: coord.map(v => Number((v / (v < FIXED_WIDTH ? FIXED_WIDTH : FIXED_HEIGHT)).toFixed(3))),
      };
    });

    return {
      list_camera: [{
        cam_info: {
          url: cameraData.rtspUrl || '',
          cam_id: crypto.randomUUID?.() || `cam-${Date.now()}`,
        },
        config: {
          direction: [],
          heatmap: {},
          layout: {},
          zone: formattedZones,
          reid: {
            faiss_switch: 0.6,
            faiss_staff_db: 0.8,
          },
        },
      }],
    };
  };

  const output = generateOutput();
  const jsonString = JSON.stringify(output, null, 2);

  const isCompleteReady =
    zoneName.trim() &&
    currentZone.lines.length >= 2 &&
    currentZone.polyPoints.length >= 3;

  return (
    <div style={{ fontFamily: 'Segoe UI, sans-serif', maxWidth: '1100px', margin: '0 auto', padding: '20px' }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '24px',
      }}>
        <h2 style={{ margin: 0, color: '#2c3e50' }}>Vẽ vùng giám sát (Zones)</h2>
        <div style={{
          background: '#3498db',
          color: 'white',
          padding: '8px 16px',
          borderRadius: '20px',
          fontWeight: 600,
        }}>
          {zones.length} zone
        </div>
      </div>

      {/* Tên zone */}
      <div style={{ marginBottom: '24px' }}>
        <label style={{ display: 'block', marginBottom: '8px', fontWeight: 600, color: '#34495e' }}>
          Tên zone
        </label>
        <input
          value={zoneName}
          onChange={e => setZoneName(e.target.value)}
          placeholder="Ví dụ: Cửa chính, Khu vực xếp hàng, Bãi đỗ xe..."
          style={{
            width: '100%',
            padding: '12px 16px',
            border: '1px solid #bdc3c7',
            borderRadius: '8px',
            fontSize: '15px',
          }}
        />
      </div>

      {/* Progress steps */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1fr 1fr',
        gap: '16px',
        marginBottom: '28px',
      }}>
        {[
          { num: 1, title: 'Axis', done: currentZone.lines.length >= 1 },
          { num: 2, title: 'Coord (hướng)', done: currentZone.lines.length >= 2 },
          { num: 3, title: 'Vùng Polygon', done: currentZone.polyPoints.length >= 3, count: currentZone.polyPoints.length },
        ].map(step => (
          <div
            key={step.num}
            style={{
              padding: '16px',
              background: currentStep === step.num ? '#ebf5ff' : '#f8f9fa',
              border: `2px solid ${step.done ? '#27ae60' : '#ecf0f1'}`,
              borderRadius: '10px',
              textAlign: 'center',
            }}
          >
            <div style={{ fontSize: '28px', fontWeight: 700, color: step.done ? '#27ae60' : '#95a5a6' }}>
              {step.num}
            </div>
            <div style={{ fontWeight: 600, margin: '6px 0 4px' }}>{step.title}</div>
            <div style={{ color: step.done ? '#27ae60' : '#7f8c8d' }}>
              {step.done ? '✓ Hoàn thành' : step.count !== undefined ? `${step.count}/≥3` : 'Chưa làm'}
            </div>
          </div>
        ))}
      </div>

      {/* Canvas */}
      <div style={{ marginBottom: '28px', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 16px rgba(0,0,0,0.08)' }}>
        <canvas
          ref={canvasRef}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={() => setDrawing(false)}
          style={{
            width: '100%',
            height: 'auto',
            display: 'block',
            cursor: currentStep === 3 ? 'crosshair' : 'default',
          }}
        />
      </div>

      {/* Controls */}
      <div style={{ display: 'flex', gap: '12px', marginBottom: '32px' }}>
        <button
          onClick={completeCurrentZone}
          disabled={!isCompleteReady}
          style={{
            flex: 1,
            padding: '14px',
            fontSize: '16px',
            fontWeight: 600,
            background: isCompleteReady ? '#27ae60' : '#95a5a6',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            cursor: isCompleteReady ? 'pointer' : 'not-allowed',
          }}
        >
          ✓ Hoàn thành zone này
        </button>
      </div>

      {/* Danh sách zones */}
      {zones.length > 0 && (
        <div style={{ marginBottom: '32px' }}>
          <h3 style={{ margin: '0 0 12px', color: '#2c3e50' }}>Các zone đã tạo</h3>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
            {zones.map((z, i) => (
              <div
                key={i}
                onClick={() => setSelectedZoneIndex(i)}
                style={{
                  padding: '10px 16px',
                  background: selectedZoneIndex === i ? '#3498db' : '#ecf0f1',
                  color: selectedZoneIndex === i ? 'white' : '#2c3e50',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '12px',
                  border: selectedZoneIndex === i ? '2px solid #2980b9' : '1px solid #bdc3c7',
                }}
              >
                <span style={{ fontWeight: 600 }}>{z.name}</span>
                <button
                  onClick={e => {
                    e.stopPropagation();
                    deleteZone(i);
                  }}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: selectedZoneIndex === i ? 'white' : '#e74c3c',
                    fontSize: '18px',
                    fontWeight: 'bold',
                    cursor: 'pointer',
                    lineHeight: 1,
                  }}
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* JSON Preview */}
      <div style={{
        background: '#1e272e',
        color: '#ecf0f1',
        padding: '20px',
        borderRadius: '10px',
        marginBottom: '32px',
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
          <h4 style={{ margin: 0 }}>Kết quả JSON ({zones.length} zones)</h4>
          <button
            onClick={() => {
              navigator.clipboard.writeText(jsonString);
              alert('Đã sao chép JSON!');
            }}
            style={{
              padding: '8px 16px',
              background: '#3498db',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer',
            }}
          >
            Copy JSON
          </button>
        </div>
        <pre style={{
          margin: 0,
          fontSize: '13px',
          maxHeight: '220px',
          overflow: 'auto',
          background: '#2f3640',
          padding: '16px',
          borderRadius: '8px',
        }}>
          {jsonString}
        </pre>
      </div>

      {/* Action buttons */}
      <div style={{ display: 'flex', gap: '16px' }}>
        <button onClick={onBack} style={{ flex: 1, padding: '14px', fontSize: '16px' }}>
          ← Quay lại
        </button>
        <button
          onClick={() => {
            resetCurrentZone();
            setZones([]);
            setSelectedZoneIndex(null);
          }}
          style={{ flex: 1, padding: '14px', fontSize: '16px', background: '#f39c12', color: 'white' }}
        >
          Đặt lại tất cả
        </button>
        <button
          onClick={() => onSave(output.list_camera[0].config)}
          disabled={zones.length === 0}
          style={{
            flex: 1,
            padding: '14px',
            fontSize: '16px',
            background: zones.length > 0 ? '#27ae60' : '#95a5a6',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            cursor: zones.length > 0 ? 'pointer' : 'not-allowed',
          }}
        >
          Lưu tất cả ({zones.length})
        </button>
      </div>
    </div>
  );
}

export default DrawingCanvas;
